import Balancer from 'react-wrap-balancer'
import { Icon } from '../../shared/dynamic-icon/dynamic-icon'
import { icons } from 'lucide-react'

export interface GridCardsProps {
  title: string
  items: {
    title: string
    description: string
    icon: string
  }[]
}

export function GridCards({ title, items }: Readonly<GridCardsProps>) {
  if (!items || items.length === 0) {
    return null
  }

  return (
    <div className="flex flex-col gap-8">
      {title && (
        <h2 className="text-center text-2xl font-bold">
          <Balancer balance={0.5}>{title}</Balancer>
        </h2>
      )}
      {items && items.length > 0 && (
        <ul className="m-0 grid list-none grid-cols-1 gap-4 p-0 md:grid-cols-2">
          {items.map((item, index) => (
            <li key={`${item.title}-${index}`} className="h-full">
              <article
                className="bg-card/60 h-full rounded-lg border p-6 shadow-none"
                aria-labelledby={`card-title-${index}`}
              >
                <div>
                  {item.icon && (
                    <Icon
                      name={item.icon as keyof typeof icons}
                      className="mb-2 size-5"
                    />
                  )}
                  <h3
                    id={`card-title-${index}`}
                    className="mb-2 text-lg font-semibold"
                  >
                    {item.title}
                  </h3>
                  {item.description && (
                    <p className="text-muted-foreground text-base">
                      <Balancer balance={0.5}>{item.description}</Balancer>
                    </p>
                  )}
                </div>
              </article>
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}

import { GridCards, type GridCardsProps } from './grid-cards'

export const values = {
  title: 'What we offer',
  items: [
    {
      title: 'Modern Design',
      description:
        'Beautiful and contemporary UI components that make your projects stand out.',
      icon: 'Palette',
    },
    {
      title: 'Developer Experience',
      description:
        'Built with developers in mind. Easy to use, well documented, and highly customizable.',
      icon: 'Code',
    },
    {
      title: 'Community Driven',
      description:
        'Join thousands of developers contributing to make UI development better for everyone.',
      icon: 'Users',
    },
    {
      title: 'Fast Performance',
      description: 'Optimized for speed and efficiency right out of the box.',
      icon: 'Zap',
    },
  ],
} satisfies GridCardsProps

export function GridCardsExample() {
  return <GridCards title={values.title} items={values.items} />
}
